#include<bits/stdc++.h>
using namespace std;
long long n, zong;
map<long long, long long> m;
long long han(long long x) {
	long long ans=1,i=x;
	for (long long j = 2; j * j <= i && x > 1; j++) {
		if (x % j == 0) {
			long long num = 1;
			while (x % j == 0) {
				x /= j;
				num *= j;
			}
			ans *= (num / j * (j - 1));

		}
	}
	if (x > 1) {
		ans *= (x - 1);
	}
	return ans;
}
int main() {
	cin >> n;
	for (long long i = 1; i * i <= n; i++) {
		if (n % i == 0) {
			zong += han(n/i) * i;
			if (n / i != i) zong += han(i) * (n / i);
		}
	}
	cout << zong;
	return 0;
}
